css:
/* Luffy Darken Theme - Professional CSS */
/* Blue & Black aesthetic with chat background image */

:root {
  --primary-blue: #3a86ff;
  --primary-blue-dark: #0050b3;
  --primary-blue-light: #7cb5ff;
  --bg-primary: #0a0a0b;
  --bg-secondary: #0f0f10;
  --bg-tertiary: #111113;
  --bg-hover: #1a1a1d;
  --text-primary: #dbdee1;
  --text-secondary: #b5bac1;
  --text-muted: #72767d;
}

/* Chat background with image */
.chat-1bRaxu, .messagesWrapper-1mRqco, [class*="scroller"] {
  background-image: url('https://raw.githubusercontent.com/a67680293-sys/Revenge-theme/main/66ff8b8e6fe1d286aa44bab423133458.jpg') !important;
  background-size: cover !important;
  background-position: center !important;
  background-attachment: fixed !important;
  background-repeat: no-repeat !important;
}

/* Main app background */
body, html, #app-mount, .appMount-3 {
  background-color: var(--bg-primary) !important;
}

/* Sidebar backgrounds */
.guilds-1SWlCJ, .guildListItem-3SmSlK {
  background-color: var(--bg-primary) !important;
}

.channels-1sY5ga, .privateChannels-oVCQqj {
  background-color: var(--bg-secondary) !important;
}

.members-1998pB {
  background-color: var(--bg-secondary) !important;
}

/* Header styling */
.header-1XpmZs, .titleBar-ac7pgm, [class*="header"] {
  background-color: var(--bg-secondary) !important;
  border-bottom: 1px solid rgba(58, 134, 255, 0.15) !important;
}

/* Channel list items */
.channelName-1QajIX, .nameDefaultText-24M0Re {
  color: var(--text-secondary) !important;
}

.channelName-1QajIX:hover {
  color: var(--primary-blue) !important;
}

/* Channel icon (hash) */
.icon-2W8DHg, [class*="hash"] {
  color: var(--primary-blue) !important;
}

/* Message styling */
.message-2QY9dM {
  background-color: transparent !important;
}

.message-2QY9dM:hover {
  background-color: rgba(58, 134, 255, 0.08) !important;
}

.messageContent-2qWWxC {
  color: var(--text-primary) !important;
}

/* Username styling */
.username-1dep7p, [class*="username"] {
  color: var(--text-primary) !important;
  font-weight: 600;
}

/* Timestamp styling */
.timestamp-3ZCmNB, [class*="timestamp"] {
  color: var(--text-muted) !important;
  font-size: 12px;
}

/* Primary buttons */
.button-1ZD-K6[class*="primary"], [class*="buttonPrimary"] {
  background-color: var(--primary-blue) !important;
  border-color: var(--primary-blue) !important;
  color: #FFFFFF !important;
  font-weight: 600;
}

.button-1ZD-K6[class*="primary"]:hover, [class*="buttonPrimary"]:hover {
  background-color: var(--primary-blue-dark) !important;
}

/* Secondary buttons */
.button-1ZD-K6[class*="secondary"], [class*="buttonSecondary"] {
  background-color: var(--bg-tertiary) !important;
  border-color: rgba(58, 134, 255, 0.3) !important;
  color: var(--text-primary) !important;
}

.button-1ZD-K6[class*="secondary"]:hover, [class*="buttonSecondary"]:hover {
  background-color: var(--bg-hover) !important;
  border-color: var(--primary-blue) !important;
}

/* Danger buttons */
.button-1ZD-K6[class*="danger"], [class*="buttonDanger"] {
  background-color: #f83838 !important;
  border-color: #f83838 !important;
  color: #FFFFFF !important;
}

.button-1ZD-K6[class*="danger"]:hover, [class*="buttonDanger"]:hover {
  background-color: #e02929 !important;
}

/* Input fields */
input, textarea, select {
  background-color: var(--bg-tertiary) !important;
  color: var(--text-primary) !important;
  border: 1px solid rgba(58, 134, 255, 0.2) !important;
  border-radius: 6px !important;
}

input:focus, textarea:focus, select:focus {
  border-color: var(--primary-blue) !important;
  outline: none !important;
  box-shadow: 0 0 0 2px rgba(58, 134, 255, 0.15) !important;
}

input::placeholder, textarea::placeholder {
  color: var(--text-muted) !important;
}

/* Modal styling */
.modal-yWgWj- {
  background-color: var(--bg-secondary) !important;
}

.modalHeader-1ba-qa {
  background-color: var(--bg-tertiary) !important;
  border-bottom: 1px solid rgba(58, 134, 255, 0.15) !important;
}

/* Popout styling */
.popout-VsKjZd {
  background-color: var(--bg-secondary) !important;
  border: 1px solid rgba(58, 134, 255, 0.2) !important;
}

/* Tooltip styling */
.tooltip-2QfLtc {
  background-color: var(--bg-tertiary) !important;
  color: var(--text-primary) !important;
}

/* Scrollbar styling */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-thumb {
  background: rgba(58, 134, 255, 0.5) !important;
  border-radius: 4px;
}

::-webkit-scrollbar-track {
  background: rgba(10, 10, 11, 0.5) !important;
}

/* Links */
a, [class*="link"] {
  color: var(--primary-blue) !important;
  text-decoration: none !important;
}

a:hover, [class*="link"]:hover {
  color: var(--primary-blue-light) !important;
  text-decoration: underline !important;
}

/* Mentions */
.mention-3XBnnM, .mention {
  background-color: rgba(58, 134, 255, 0.15) !important;
  color: var(--primary-blue) !important;
  border-radius: 4px;
  padding: 0 4px;
  font-weight: 600;
}

.mention:hover {
  background-color: rgba(58, 134, 255, 0.25) !important;
}

/* Embed styling */
[class*="embed"] {
  background-color: var(--bg-tertiary) !important;
  border-left: 4px solid var(--primary-blue) !important;
}

[class*="embedTitle"] {
  color: var(--primary-blue) !important;
}

/* Reactions */
[class*="reaction"] {
  background-color: var(--bg-tertiary) !important;
  border: 1px solid rgba(58, 134, 255, 0.2) !important;
}

[class*="reaction"]:hover {
  background-color: rgba(58, 134, 255, 0.15) !important;
  border-color: var(--primary-blue) !important;
}

/* Status indicators */
[class*="statusOnline"] {
  background-color: #43b581 !important;
}

[class*="statusIdle"] {
  background-color: #faa61a !important;
}

[class*="statusDND"] {
  background-color: #f83838 !important;
}

[class*="statusOffline"] {
  background-color: #72767d !important;
}

/* Context menu */
[class*="contextMenu"] {
  background-color: var(--bg-secondary) !important;
  border: 1px solid rgba(58, 134, 255, 0.2) !important;
}

[class*="contextMenu"] [class*="item"]:hover {
  background-color: rgba(58, 134, 255, 0.15) !important;
}

/* Search bar */
[class*="searchBar"] {
  background-color: var(--bg-tertiary) !important;
  border: 1px solid rgba(58, 134, 255, 0.2) !important;
}

[class*="searchBar"]:focus-within {
  border-color: var(--primary-blue) !important;
}

/* Badge styling */
[class*="badge"] {
  background-color: var(--primary-blue) !important;
  color: #FFFFFF !important;
}

/* Divider styling */
[class*="divider"] {
  background-color: rgba(255, 255, 255, 0.1) !important;
}

/* Settings tab */
[class*="settingsTab"] {
  color: var(--text-secondary) !important;
}

[class*="settingsTab"]:hover {
  background-color: rgba(58, 134, 255, 0.1) !important;
}

[class*="settingsTab"][class*="selected"] {
  background-color: rgba(58, 134, 255, 0.15) !important;
  color: var(--primary-blue) !important;
  border-left: 3px solid var(--primary-blue) !important;
}

/* Voice channel styling */
[class*="voiceUser"] {
  background-color: var(--bg-tertiary) !important;
}

[class*="voiceUser"]:hover {
  background-color: rgba(58, 134, 255, 0.1) !important;
}

/* Category name */
[class*="categoryName"] {
  color: var(--primary-blue) !important;
  font-weight: 700;
}

/* Member item */
[class*="member"] {
  color: var(--text-secondary) !important;
}

[class*="member"]:hover {
  background-color: rgba(58, 134, 255, 0.08) !important;
}

/* Typing indicator */
[class*="typing"] {
  color: var(--text-muted) !important;
}

/* Spoiler text */
[class*="spoilerText"] {
  background-color: var(--bg-tertiary) !important;
}

[class*="spoilerText"][class*="hidden"] {
  background-color: var(--bg-hover) !important;
}

/* Message group wrapper */
[class*="messageGroupWrapper"] {
  background-color: transparent !important;
}

[class*="messageGroupWrapper"]:hover {
  background-color: rgba(58, 134, 255, 0.05) !important;
}

/* Attachment styling */
[class*="attachment"] {
  background-color: var(--bg-tertiary) !important;
  border: 1px solid rgba(58, 134, 255, 0.2) !important;
}

/* Thread styling */
[class*="thread"] {
  background-color: transparent !important;
}

[class*="threadSpine"] {
  background-color: var(--primary-blue) !important;
}

/* User profile */
[class*="userProfile"] {
  background-color: var(--bg-secondary) !important;
}

/* Activity card */
[class*="activityCard"] {
  background-color: var(--bg-tertiary) !important;
  border: 1px solid rgba(58, 134, 255, 0.15) !important;
}

/* Notification styling */
[class*="notification"] {
  background-color: var(--bg-secondary) !important;
  border-left: 3px solid var(--primary-blue) !important;
}

/* Toast styling */
[class*="toast"] {
  background-color: var(--bg-secondary) !important;
  border: 1px solid rgba(58, 134, 255, 0.2) !important;
}

/* Role pill */
[class*="rolePill"] {
  background-color: var(--bg-tertiary) !important;
  border: 1px solid rgba(58, 134, 255, 0.3) !important;
}

/* Autocomplete */
[class*="autocomplete"] {
  background-color: var(--bg-secondary) !important;
  border: 1px solid rgba(58, 134, 255, 0.2) !important;
}

/* Option styling */
[class*="option"] {
  background-color: var(--bg-tertiary) !important;
  color: var(--text-secondary) !important;
}

[class*="option"]:hover {
  background-color: rgba(58, 134, 255, 0.15) !important;
}

/* Selected option */
[class*="option"][class*="selected"] {
  background-color: rgba(58, 134, 255, 0.25) !important;
  color: var(--primary-blue) !important;
}

/* Panel styling */
[class*="panel"] {
  background-color: var(--bg-secondary) !important;
}

/* Invite button */
[class*="inviteButton"] {
  background-color: var(--primary-blue) !important;
  color: #FFFFFF !important;
}

[class*="inviteButton"]:hover {
  background-color: var(--primary-blue-dark) !important;
}

/* Call container */
[class*="callContainer"] {
  background-color: var(--bg-secondary) !important;
}

/* Voice state */
[class*="voiceState"] {
  background-color: var(--bg-tertiary) !important;
}

/* User popout */
.userPopout-3XzG_A {
  background-color: var(--bg-secondary) !important;
  border: 1px solid rgba(58, 134, 255, 0.2) !important;
}

/* Keyboard styling */
[class*="keyboard"] {
  background-color: var(--bg-secondary) !important;
}

/* Unread badge */
[class*="unread"] {
  background-color: var(--primary-blue) !important;
}

/* Mention line */
[class*="mentionLine"] {
  background-color: var(--primary-blue) !important;
}

/* Forum post */
[class*="forumPost"] {
  background-color: var(--bg-tertiary) !important;
  border: 1px solid rgba(58, 134, 255, 0.15) !important;
}

/* Spinner */
[class*="spinner"] circle {
  stroke: var(--primary-blue) !important;
}

/* Loading animation */
[class*="loading"] {
  color: var(--primary-blue) !important;
}

/* General text color fix */
span, div, p, h1, h2, h3, h4, h5, h6 {
  color: var(--text-primary) !important;
}

/* Secondary text */
[class*="secondary"] {
  color: var(--text-secondary) !important;
}

/* Muted text */
[class*="muted"] {
  color: var(--text-muted) !important;
}

/* Placeholder text */
::placeholder {
  color: var(--text-muted) !important;
}

/* Focus states */
*:focus {
  outline: 2px solid rgba(58, 134, 255, 0.3) !important;
  outline-offset: 2px !important;
}

/* Transition smoothness */
* {
  transition: background-color 0.2s ease, color 0.2s ease, border-color 0.2s ease !important;
}
